import requests
import time


def _post_with_retry(endpoint: str, payload: dict, headers: dict|None = None) -> dict|None:
        """
        Send HTTP POST with retry logic.

        Args:
            endpoint (str): API endpoint path
            payload (dict: JSON body

        Returns:
            dict, optional: Response JSON on success, None on failure
        """
        url = "http://172.20.10.3:8000" + endpoint

        for attempt in range(2 + 1):
            response = None
            try:
                print("request")
                response = requests.post(url, data=payload, headers=headers, timeout=8)
                print("done")
                if 200 <= response.status_code < 300:
                    try:
                        data = response.json()
                    except Exception:
                        data = {"status": "ok"}
                    return data
            except Exception as e:
                print(e)
            finally:
                if response is not None:
                    response.close()
                    
            if attempt < 2:
                time.sleep(200)

        return None



